import React, { useState } from 'react';
import { Outlet, useNavigate, useLocation } from 'react-router-dom';
import {
  Box, Drawer, AppBar, Toolbar, List, Typography, Divider, IconButton,
  ListItem, ListItemButton, ListItemIcon, ListItemText, useMediaQuery
} from '@mui/material';
import {
  Menu as MenuIcon, Dashboard as DashboardIcon, Business as BusinessIcon,
  AttachMoney as MoneyIcon, Psychology as MindsetIcon, School as SchoolIcon,
  FitnessCenter as HealthIcon, CheckCircle as CheckIcon,
  Assessment as ReportsIcon, SmartToy as AIIcon, Logout as LogoutIcon,
  EmojiEvents as TrophyIcon
} from '@mui/icons-material';
import { useAuth } from '../context/AuthContext';

const drawerWidth = 240;

const menuItems = [
  { text: 'Dashboard', icon: <DashboardIcon />, path: '/' },
  { text: 'Business', icon: <BusinessIcon />, path: '/business' },
  { text: 'Best Idea', icon: <TrophyIcon />, path: '/best-idea' },
  { text: 'Financial', icon: <MoneyIcon />, path: '/financial' },
  { text: 'Mindset', icon: <MindsetIcon />, path: '/mindset' },
  { text: 'Learning', icon: <SchoolIcon />, path: '/learning' },
  { text: 'Health', icon: <HealthIcon />, path: '/health' },
  { text: 'Check-in', icon: <CheckIcon />, path: '/checkin' },
  { text: 'Reports', icon: <ReportsIcon />, path: '/reports' },
  { text: 'AI Advisor', icon: <AIIcon />, path: '/ai' },
];

export default function Layout() {
  const [mobileOpen, setMobileOpen] = useState(false);
  const navigate = useNavigate();
  const location = useLocation();
  const { user, logout } = useAuth();
  const isMobile = useMediaQuery('(max-width:600px)');

  const handleDrawerToggle = () => setMobileOpen(!mobileOpen);

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  const drawer = (
    <div>
      <Toolbar sx={{ px: 2 }}>
        <Typography variant="h6" noWrap fontWeight={700} sx={{ color: '#f1f5f9', letterSpacing: '-0.5px' }}>
          Sirawdink OS
        </Typography>
      </Toolbar>
      <Divider sx={{ borderColor: '#1e293b' }} />
      <List sx={{ px: 1, pt: 1 }}>
        {menuItems.map((item) => {
          const isActive = location.pathname === item.path ||
            (item.path !== '/' && location.pathname.startsWith(item.path));
          return (
            <ListItem key={item.text} disablePadding sx={{ mb: 0.5 }}>
              <ListItemButton
                onClick={() => {
                  navigate(item.path);
                  if (isMobile) setMobileOpen(false);
                }}
                sx={{
                  borderRadius: 2,
                  bgcolor: isActive ? '#1e40af' : 'transparent',
                  '&:hover': { bgcolor: isActive ? '#1d4ed8' : '#1e293b' },
                  transition: 'all 0.15s',
                }}
              >
                <ListItemIcon sx={{ minWidth: 40, color: isActive ? '#93c5fd' : '#64748b' }}>
                  {item.icon}
                </ListItemIcon>
                <ListItemText
                  primary={item.text}
                  primaryTypographyProps={{
                    fontWeight: isActive ? 700 : 500,
                    color: isActive ? '#e2e8f0' : '#94a3b8',
                    fontSize: '0.9rem'
                  }}
                />
              </ListItemButton>
            </ListItem>
          );
        })}
      </List>
      <Divider sx={{ borderColor: '#1e293b', mt: 1 }} />
      <List sx={{ px: 1, pt: 1 }}>
        <ListItem disablePadding>
          <ListItemButton
            onClick={handleLogout}
            sx={{ borderRadius: 2, '&:hover': { bgcolor: '#1e293b' } }}
          >
            <ListItemIcon sx={{ minWidth: 40, color: '#64748b' }}>
              <LogoutIcon />
            </ListItemIcon>
            <ListItemText
              primary="Logout"
              primaryTypographyProps={{ color: '#64748b', fontSize: '0.9rem' }}
            />
          </ListItemButton>
        </ListItem>
      </List>
    </div>
  );

  return (
    <Box sx={{ display: 'flex', bgcolor: '#0a1929', minHeight: '100vh' }}>
      <AppBar
        position="fixed"
        sx={{
          zIndex: (theme) => theme.zIndex.drawer + 1,
          bgcolor: '#0d1b2a',
          borderBottom: '1px solid #1e293b',
          boxShadow: 'none'
        }}
      >
        <Toolbar>
          <IconButton
            color="inherit"
            edge="start"
            onClick={handleDrawerToggle}
            sx={{ mr: 2, display: { sm: 'none' } }}
          >
            <MenuIcon />
          </IconButton>
          <Typography variant="h6" noWrap component="div" sx={{ flexGrow: 1, fontWeight: 700, color: '#f1f5f9' }}>
            {menuItems.find(m => m.path === location.pathname)?.text || 'Sirawdink OS'}
          </Typography>
          <Typography variant="body2" sx={{ color: '#64748b' }}>
            {user?.username}
          </Typography>
        </Toolbar>
      </AppBar>

      <Box component="nav" sx={{ width: { sm: drawerWidth }, flexShrink: { sm: 0 } }}>
        <Drawer
          variant={isMobile ? 'temporary' : 'permanent'}
          open={isMobile ? mobileOpen : true}
          onClose={handleDrawerToggle}
          ModalProps={{ keepMounted: true }}
          sx={{
            '& .MuiDrawer-paper': {
              boxSizing: 'border-box',
              width: drawerWidth,
              bgcolor: '#0d1b2a',
              borderRight: '1px solid #1e293b',
            },
          }}
        >
          {drawer}
        </Drawer>
      </Box>

      <Box
        component="main"
        sx={{
          flexGrow: 1,
          p: 0,
          width: { sm: `calc(100% - ${drawerWidth}px)` },
          bgcolor: '#0a1929',
          minHeight: '100vh'
        }}
      >
        <Toolbar />
        <Outlet />
      </Box>
    </Box>
  );
}
